inline void compute_velocity(float density, const float3& momentum, float3* velocity) {
    velocity->x = momentum.x / density;
    velocity->y = momentum.y / density;
    velocity->z = momentum.z / density;
}

inline float compute_speed_sqd(const float3& velocity) {
    return velocity.x * velocity.x + velocity.y * velocity.y + velocity.z * velocity.z;
}

inline float compute_pressure(float density, float density_energy, float speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

inline float compute_speed_of_sound(float density, float pressure) {
    return std::sqrt(GAMMA * pressure / density);
}

inline void compute_flux_contribution(float density, const float3& momentum, float density_energy, float pressure,
                                      const float3& velocity, float3* fc_momentum_x, float3* fc_momentum_y,
                                      float3* fc_momentum_z, float3* fc_density_energy) {
    fc_momentum_x->x = velocity.x * momentum.x + pressure;
    fc_momentum_x->y = velocity.x * momentum.y;
    fc_momentum_x->z = velocity.x * momentum.z;

    fc_momentum_y->x = fc_momentum_x->y;
    fc_momentum_y->y = velocity.y * momentum.y + pressure;
    fc_momentum_y->z = velocity.y * momentum.z;

    fc_momentum_z->x = fc_momentum_x->z;
    fc_momentum_z->y = fc_momentum_y->z;
    fc_momentum_z->z = velocity.z * momentum.z + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy->x = velocity.x * de_p;
    fc_density_energy->y = velocity.y * de_p;
    fc_density_energy->z = velocity.z * de_p;
}

inline void compute_flux_contribution(float& density, float3& momentum, float& density_energy, float& pressure,
                                      float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y,
                                      float3& fc_momentum_z, float3& fc_density_energy) {
    compute_flux_contribution(density, momentum, density_energy, pressure, velocity,
                              &fc_momentum_x, &fc_momentum_y, &fc_momentum_z, &fc_density_energy);
}

void initialize_variables(int nelr, float* variables, const float* ff_variable) {
#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        for (int j = 0; j < NVAR; j++) {
            variables[i + j * nelr] = ff_variable[j];
        }
    }
}

void compute_step_factor(int nelr, const float* variables, const float* areas, float* step_factors) {
#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density = variables[i + VAR_DENSITY * nelr];
        float3 momentum;
        momentum.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
        momentum.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
        momentum.z = variables[i + (VAR_MOMENTUM + 2) * nelr];

        float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        float3 velocity;
        compute_velocity(density, momentum, &velocity);
        float speed_sqd = compute_speed_sqd(velocity);
        float pressure = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5f / (std::sqrt(areas[i]) * (std::sqrt(speed_sqd) + speed_of_sound));
    }
}

void compute_flux(int nelr, const int* elements_surrounding_elements, const float* normals, const float* variables,
                  const float* ff_variable, float* fluxes, const float3* ff_flux_contribution_density_energy,
                  const float3* ff_flux_contribution_momentum_x, const float3* ff_flux_contribution_momentum_y,
                  const float3* ff_flux_contribution_momentum_z) {
    const float smoothing_coefficient = 0.2f;

#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        int j, nb;
        float3 normal;
        float normal_len;
        float factor;

        float density_i = variables[i + VAR_DENSITY * nelr];
        float3 momentum_i;
        momentum_i.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
        momentum_i.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
        momentum_i.z = variables[i + (VAR_MOMENTUM + 2) * nelr];

        float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        float3 velocity_i;
        compute_velocity(density_i, momentum_i, &velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);

        float speed_i = std::sqrt(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);
        float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
        float3 flux_contribution_i_density_energy;
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
                                  &flux_contribution_i_momentum_x, &flux_contribution_i_momentum_y,
                                  &flux_contribution_i_momentum_z, &flux_contribution_i_density_energy);

        float flux_i_density = 0.0f;
        float3 flux_i_momentum;
        flux_i_momentum.x = 0.0f;
        flux_i_momentum.y = 0.0f;
        flux_i_momentum.z = 0.0f;
        float flux_i_density_energy = 0.0f;

        float3 velocity_nb;
        float density_nb, density_energy_nb;
        float3 momentum_nb;
        float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
        float3 flux_contribution_nb_density_energy;
        float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

        for (j = 0; j < NNB; j++) {
            nb = elements_surrounding_elements[i + j * nelr];
            normal.x = normals[i + (j + 0 * NNB) * nelr];
            normal.y = normals[i + (j + 1 * NNB) * nelr];
            normal.z = normals[i + (j + 2 * NNB) * nelr];

            normal_len = std::sqrt(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

            if (nb >= 0) {
                density_nb = variables[nb + VAR_DENSITY * nelr];
                momentum_nb.x = variables[nb + (VAR_MOMENTUM + 0) * nelr];
                momentum_nb.y = variables[nb + (VAR_MOMENTUM + 1) * nelr];
                momentum_nb.z = variables[nb + (VAR_MOMENTUM + 2) * nelr];
                density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];
                compute_velocity(density_nb, momentum_nb, &velocity_nb);
                speed_sqd_nb = compute_speed_sqd(velocity_nb);
                pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
                                          &flux_contribution_nb_momentum_x, &flux_contribution_nb_momentum_y,
                                          &flux_contribution_nb_momentum_z, &flux_contribution_nb_density_energy);

                factor = -normal_len * smoothing_coefficient * 0.5f *
                         (speed_i + std::sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
                flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
                flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

                factor = 0.5f * normal.x;
                flux_i_density += factor * (momentum_nb.x + momentum_i.x);
                flux_i_density_energy += factor * (flux_contribution_nb_density_energy.x + flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.x + flux_contribution_i_momentum_z.x);

                factor = 0.5f * normal.y;
                flux_i_density += factor * (momentum_nb.y + momentum_i.y);
                flux_i_density_energy += factor * (flux_contribution_nb_density_energy.y + flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.y + flux_contribution_i_momentum_z.y);

                factor = 0.5f * normal.z;
                flux_i_density += factor * (momentum_nb.z + momentum_i.z);
                flux_i_density_energy += factor * (flux_contribution_nb_density_energy.z + flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.z + flux_contribution_i_momentum_z.z);
            } else if (nb == -1) {
                flux_i_momentum.x += normal.x * pressure_i;
                flux_i_momentum.y += normal.y * pressure_i;
                flux_i_momentum.z += normal.z * pressure_i;
            } else if (nb == -2) {
                factor = 0.5f * normal.x;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0].x + flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0].x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0].x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0].x + flux_contribution_i_momentum_z.x);

                factor = 0.5f * normal.y;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0].y + flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0].y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0].y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0].y + flux_contribution_i_momentum_z.y);

                factor = 0.5f * normal.z;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
                flux_i_density_energy += factor * (ff_flux_contribution_density_energy[0].z + flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0].z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0].z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0].z + flux_contribution_i_momentum_z.z);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum.x;
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum.y;
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum.z;
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

void time_step(int j, int nelr, const float* old_variables, float* variables, const float* step_factors, const float* fluxes) {
#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float factor = step_factors[i] / float(RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] =
            old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] =
            old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] =
            old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] =
            old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] =
            old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

void _clCmdParams(int argc, char* argv[]) {
    (void)argc;
    (void)argv;
}
void _clStatistics() {}
void _clPrintTiming() {}

int main(int argc, char** argv) {
    std::printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n",
                BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

    if (argc < 2) {
        std::cout << "specify data file name and [device type] [device id]" << std::endl;
        return 0;
    }

    const char* data_file_name = argv[1];
    _clCmdParams(argc, argv);

    float* ff_variable = nullptr;
    float3* ff_flux_contribution_momentum_x = nullptr;
    float3* ff_flux_contribution_momentum_y = nullptr;
    float3* ff_flux_contribution_momentum_z = nullptr;
    float3* ff_flux_contribution_density_energy = nullptr;

    float* areas = nullptr;
    int* elements_surrounding_elements = nullptr;
    float* normals = nullptr;

    float* variables = nullptr;
    float* old_variables = nullptr;
    float* fluxes = nullptr;
    float* step_factors = nullptr;

    float h_ff_variable[NVAR];

    try {
        {
            const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

            h_ff_variable[VAR_DENSITY] = 1.4f;

            float ff_pressure = 1.0f;
            float ff_speed_of_sound = std::sqrt(GAMMA * ff_pressure / h_ff_variable[VAR_DENSITY]);
            float ff_speed = float(ff_mach) * ff_speed_of_sound;

            float3 ff_velocity;
            ff_velocity.x = ff_speed * float(std::cos((float)angle_of_attack));
            ff_velocity.y = ff_speed * float(std::sin((float)angle_of_attack));
            ff_velocity.z = 0.0f;

            h_ff_variable[VAR_MOMENTUM + 0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
            h_ff_variable[VAR_MOMENTUM + 1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
            h_ff_variable[VAR_MOMENTUM + 2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

            h_ff_variable[VAR_DENSITY_ENERGY] =
                h_ff_variable[VAR_DENSITY] * (0.5f * (ff_speed * ff_speed)) + (ff_pressure / float(GAMMA - 1.0f));

            float3 h_ff_momentum;
            h_ff_momentum.x = *(h_ff_variable + VAR_MOMENTUM + 0);
            h_ff_momentum.y = *(h_ff_variable + VAR_MOMENTUM + 1);
            h_ff_momentum.z = *(h_ff_variable + VAR_MOMENTUM + 2);

            float3 h_ff_flux_contribution_momentum_x;
            float3 h_ff_flux_contribution_momentum_y;
            float3 h_ff_flux_contribution_momentum_z;
            float3 h_ff_flux_contribution_density_energy;

            compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY], ff_pressure,
                                      ff_velocity, h_ff_flux_contribution_momentum_x, h_ff_flux_contribution_momentum_y,
                                      h_ff_flux_contribution_momentum_z, h_ff_flux_contribution_density_energy);

            ff_variable = alloc<float>(NVAR);
            ff_flux_contribution_momentum_x = alloc<float3>(1);
            ff_flux_contribution_momentum_y = alloc<float3>(1);
            ff_flux_contribution_momentum_z = alloc<float3>(1);
            ff_flux_contribution_density_energy = alloc<float3>(1);

            upload(ff_variable, h_ff_variable, NVAR);
            upload(ff_flux_contribution_momentum_x, &h_ff_flux_contribution_momentum_x, 1);
            upload(ff_flux_contribution_momentum_y, &h_ff_flux_contribution_momentum_y, 1);
            upload(ff_flux_contribution_momentum_z, &h_ff_flux_contribution_momentum_z, 1);
            upload(ff_flux_contribution_density_energy, &h_ff_flux_contribution_density_energy, 1);
        }

        int nel;
        int nelr;

        {
            std::ifstream file(data_file_name);
            if (!file) {
                throw(std::string("can not find/open file!"));
            }

            file >> nel;
            nelr = block_length * ((nel / block_length) + std::min(1, nel % block_length));
            std::cout << "--cambine: nel=" << nel << ", nelr=" << nelr << std::endl;

            float* h_areas = new float[nelr];
            int* h_elements_surrounding_elements = new int[nelr * NNB];
            float* h_normals = new float[nelr * NDIM * NNB];

            for (int i = 0; i < nel; i++) {
                file >> h_areas[i];
                for (int j = 0; j < NNB; j++) {
                    file >> h_elements_surrounding_elements[i + j * nelr];
                    if (h_elements_surrounding_elements[i + j * nelr] < 0) h_elements_surrounding_elements[i + j * nelr] = -1;
                    h_elements_surrounding_elements[i + j * nelr]--;

                    for (int k = 0; k < NDIM; k++) {
                        file >> h_normals[i + (j + k * NNB) * nelr];
                        h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
                    }
                }
            }

            int last = nel - 1;
            for (int i = nel; i < nelr; i++) {
                h_areas[i] = h_areas[last];
                for (int j = 0; j < NNB; j++) {
                    h_elements_surrounding_elements[i + j * nelr] = h_elements_surrounding_elements[last + j * nelr];
                    for (int k = 0; k < NDIM; k++)
                        h_normals[last + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
                }
            }

            areas = alloc<float>(nelr);
            upload(areas, h_areas, nelr);

            elements_surrounding_elements = alloc<int>(nelr * NNB);
            upload(elements_surrounding_elements, h_elements_surrounding_elements, nelr * NNB);

            normals = alloc<float>(nelr * NDIM * NNB);
            upload(normals, h_normals, nelr * NDIM * NNB);

            delete[] h_areas;
            delete[] h_elements_surrounding_elements;
            delete[] h_normals;
        }

        variables = alloc<float>(nelr * NVAR);
        initialize_variables(nelr, variables, ff_variable);

        old_variables = alloc<float>(nelr * NVAR);
        fluxes = alloc<float>(nelr * NVAR);
        step_factors = alloc<float>(nelr);

        initialize_variables(nelr, old_variables, ff_variable);
        initialize_variables(nelr, fluxes, ff_variable);
        std::memset(step_factors, 0, sizeof(float) * (size_t)nelr);

        std::cout << "Starting..." << std::endl;

        for (int i = 0; i < iterations; i++) {
            copy(old_variables, variables, nelr * NVAR);

            compute_step_factor(nelr, variables, areas, step_factors);
            for (int j = 0; j < RK; j++) {
                compute_flux(nelr, elements_surrounding_elements, normals, variables, ff_variable, fluxes,
                             ff_flux_contribution_density_energy, ff_flux_contribution_momentum_x,
                             ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z);

                time_step(j, nelr, old_variables, variables, step_factors, fluxes);
            }
        }

        std::cout << "Saving solution..." << std::endl;
        dump(variables, nel, nelr);
        std::cout << "Saved solution..." << std::endl;
        _clStatistics();
        std::cout << "Cleaning up..." << std::endl;

        dealloc(ff_variable);
        dealloc(ff_flux_contribution_momentum_x);
        dealloc(ff_flux_contribution_momentum_y);
        dealloc(ff_flux_contribution_momentum_z);
        dealloc(ff_flux_contribution_density_energy);
        dealloc(areas);
        dealloc(elements_surrounding_elements);
        dealloc(normals);
        dealloc(variables);
        dealloc(old_variables);
        dealloc(fluxes);
        dealloc(step_factors);

        std::cout << "Done..." << std::endl;
        _clPrintTiming();
    } catch (std::string msg) {
        std::cout << "--cambine:( an exception catched in main body ->" << msg << std::endl;
        dealloc(ff_variable);
        dealloc(ff_flux_contribution_momentum_x);
        dealloc(ff_flux_contribution_momentum_y);
        dealloc(ff_flux_contribution_momentum_z);
        dealloc(ff_flux_contribution_density_energy);
        dealloc(areas);
        dealloc(elements_surrounding_elements);
        dealloc(normals);
        dealloc(variables);
        dealloc(old_variables);
        dealloc(fluxes);
        dealloc(step_factors);
    } catch (...) {
        std::cout << "--cambine:( unknow exceptions in main body..." << std::endl;
        dealloc(ff_variable);
        dealloc(ff_flux_contribution_momentum_x);
        dealloc(ff_flux_contribution_momentum_y);
        dealloc(ff_flux_contribution_momentum_z);
        dealloc(ff_flux_contribution_density_energy);
        dealloc(areas);
        dealloc(elements_surrounding_elements);
        dealloc(normals);
        dealloc(variables);
        dealloc(old_variables);
        dealloc(fluxes);
        dealloc(step_factors);
    }

    return 0;
}

#include <iostream>
#include <fstream>
#include <cmath>
#include <cstring>
#include <string>
#include <algorithm>
#include <omp.h>

#define GAMMA 1.4f
#define iterations 2000
#ifndef block_length
#define block_length 192
#endif

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#ifdef RD_WG_SIZE_1_0
#define BLOCK_SIZE_1 RD_WG_SIZE_1_0
#elif defined(RD_WG_SIZE_1)
#define BLOCK_SIZE_1 RD_WG_SIZE_1
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_1 RD_WG_SIZE
#else
#define BLOCK_SIZE_1 192
#endif

#ifdef RD_WG_SIZE_2_0
#define BLOCK_SIZE_2 RD_WG_SIZE_2_0
#elif defined(RD_WG_SIZE_2)
#define BLOCK_SIZE_2 RD_WG_SIZE_2
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_2 RD_WG_SIZE
#else
#define BLOCK_SIZE_2 192
#endif

#ifdef RD_WG_SIZE_3_0
#define BLOCK_SIZE_3 RD_WG_SIZE_3_0
#elif defined(RD_WG_SIZE_3)
#define BLOCK_SIZE_3 RD_WG_SIZE_3
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_3 RD_WG_SIZE
#else
#define BLOCK_SIZE_3 192
#endif

#ifdef RD_WG_SIZE_4_0
#define BLOCK_SIZE_4 RD_WG_SIZE_4_0
#elif defined(RD_WG_SIZE_4)
#define BLOCK_SIZE_4 RD_WG_SIZE_4
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_4 RD_WG_SIZE
#else
#define BLOCK_SIZE_4 192
#endif

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)

typedef struct {
    float x;
    float y;
    float z;
} float3;

template <typename T>
T* alloc(int N) {
    return new T[N];
}

template <typename T>
void dealloc(T* array) {
    delete[] array;
}

template <typename T>
void copy(T* dst, const T* src, int N) {
    std::memcpy(dst, src, sizeof(T) * N);
}

template <typename T>
void upload(T* dst, const T* src, int N) {
    std::memcpy(dst, src, sizeof(T) * N);
}

template <typename T>
void download(T* dst, const T* src, int N) {
    std::memcpy(dst, src, sizeof(T) * N);
}

void dump(float* variables, int nel, int nelr) {
    float* h_variables = new float[nelr * NVAR];
    download(h_variables, variables, nelr * NVAR);

    {
        std::ofstream file("density.txt");
        file << nel << " " << nelr << std::endl;
        for (int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY * nelr] << std::endl;
    }

    {
        std::ofstream file("momentum.txt");
        file << nel << " " << nelr << std::endl;
        for (int i = 0; i < nel; i++) {
            for (int j = 0; j != NDIM; j++) file << h_variables[i + (VAR_MOMENTUM + j) * nelr] << " ";
            file << std::endl;
        }
    }

    {
        std::ofstream file("density_energy.txt");
        file << nel << " " << nelr << std::endl;
        for (int i = 0; i < nel; i++) file << h_variables[i + VAR_DENSITY_ENERGY * nelr] << std::endl;
    }

    delete[] h_variables;
}

inline void compute_velocity(float density, const float3& momentum, float3& velocity) {
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
}

inline float compute_speed_sqd(const float3& velocity) {
    return velocity.x * velocity.x + velocity.y * velocity.y + velocity.z * velocity.z;
}

inline float compute_pressure(float density, float density_energy, float speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

inline float compute_speed_of_sound(float density, float pressure) {
    return sqrtf(GAMMA * pressure / density);
}

inline void compute_flux_contribution(float& density, float3& momentum, float& density_energy, float& pressure,
                                      float3& velocity, float3& fc_momentum_x, float3& fc_momentum_y,
                                      float3& fc_momentum_z, float3& fc_density_energy) {
    (void)density;
    fc_momentum_x.x = velocity.x * momentum.x + pressure;
    fc_momentum_x.y = velocity.x * momentum.y;
    fc_momentum_x.z = velocity.x * momentum.z;

    fc_momentum_y.x = fc_momentum_x.y;
    fc_momentum_y.y = velocity.y * momentum.y + pressure;
    fc_momentum_y.z = velocity.y * momentum.z;

    fc_momentum_z.x = fc_momentum_x.z;
    fc_momentum_z.y = fc_momentum_y.z;
    fc_momentum_z.z = velocity.z * momentum.z + pressure;

    float de_p = density_energy + pressure;
    fc_density_energy.x = velocity.x * de_p;
    fc_density_energy.y = velocity.y * de_p;
    fc_density_energy.z = velocity.z * de_p;
}

void initialize_variables(int nelr, float* variables, const float* ff_variable) {
#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        for (int j = 0; j < NVAR; j++) variables[i + j * nelr] = ff_variable[j];
    }
}

void compute_step_factor(int nelr, const float* variables, const float* areas, float* step_factors) {
#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float density = variables[i + VAR_DENSITY * nelr];
        float3 momentum;
        momentum.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
        momentum.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
        momentum.z = variables[i + (VAR_MOMENTUM + 2) * nelr];

        float density_energy = variables[i + VAR_DENSITY_ENERGY * nelr];

        float3 velocity;
        compute_velocity(density, momentum, velocity);
        float speed_sqd = compute_speed_sqd(velocity);

        float pressure = compute_pressure(density, density_energy, speed_sqd);
        float speed_of_sound = compute_speed_of_sound(density, pressure);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

void compute_flux(int nelr, const int* elements_surrounding_elements, const float* normals, const float* variables,
                  const float* ff_variable, float* fluxes, const float3* ff_flux_contribution_density_energy,
                  const float3* ff_flux_contribution_momentum_x, const float3* ff_flux_contribution_momentum_y,
                  const float3* ff_flux_contribution_momentum_z) {
    const float smoothing_coefficient = 0.2f;

#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        int j, nb;
        float3 normal;
        float normal_len;
        float factor;

        float density_i = variables[i + VAR_DENSITY * nelr];
        float3 momentum_i;
        momentum_i.x = variables[i + (VAR_MOMENTUM + 0) * nelr];
        momentum_i.y = variables[i + (VAR_MOMENTUM + 1) * nelr];
        momentum_i.z = variables[i + (VAR_MOMENTUM + 2) * nelr];
        float density_energy_i = variables[i + VAR_DENSITY_ENERGY * nelr];

        float3 velocity_i;
        compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);
        float speed_i = sqrtf(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
        float3 flux_contribution_i_density_energy;
        compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
                                  flux_contribution_i_momentum_x, flux_contribution_i_momentum_y,
                                  flux_contribution_i_momentum_z, flux_contribution_i_density_energy);

        float flux_i_density = 0.0f;
        float3 flux_i_momentum;
        flux_i_momentum.x = 0.0f;
        flux_i_momentum.y = 0.0f;
        flux_i_momentum.z = 0.0f;
        float flux_i_density_energy = 0.0f;

        float3 velocity_nb;
        float density_nb, density_energy_nb;
        float3 momentum_nb;
        float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
        float3 flux_contribution_nb_density_energy;
        float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

        for (j = 0; j < NNB; j++) {
            nb = elements_surrounding_elements[i + j * nelr];
            normal.x = normals[i + (j + 0 * NNB) * nelr];
            normal.y = normals[i + (j + 1 * NNB) * nelr];
            normal.z = normals[i + (j + 2 * NNB) * nelr];

            normal_len = sqrtf(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

            if (nb >= 0) {
                density_nb = variables[nb + VAR_DENSITY * nelr];
                momentum_nb.x = variables[nb + (VAR_MOMENTUM + 0) * nelr];
                momentum_nb.y = variables[nb + (VAR_MOMENTUM + 1) * nelr];
                momentum_nb.z = variables[nb + (VAR_MOMENTUM + 2) * nelr];
                density_energy_nb = variables[nb + VAR_DENSITY_ENERGY * nelr];

                compute_velocity(density_nb, momentum_nb, velocity_nb);
                speed_sqd_nb = compute_speed_sqd(velocity_nb);
                pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);
                compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
                                          flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y,
                                          flux_contribution_nb_momentum_z, flux_contribution_nb_density_energy);

                factor = -normal_len * smoothing_coefficient * 0.5f *
                         (speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor * (density_i - density_nb);
                flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
                flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
                flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

                factor = 0.5f * normal.x;
                flux_i_density += factor * (momentum_nb.x + momentum_i.x);
                flux_i_density_energy +=
                    factor * (flux_contribution_nb_density_energy.x + flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.x + flux_contribution_i_momentum_z.x);

                factor = 0.5f * normal.y;
                flux_i_density += factor * (momentum_nb.y + momentum_i.y);
                flux_i_density_energy +=
                    factor * (flux_contribution_nb_density_energy.y + flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.y + flux_contribution_i_momentum_z.y);

                factor = 0.5f * normal.z;
                flux_i_density += factor * (momentum_nb.z + momentum_i.z);
                flux_i_density_energy +=
                    factor * (flux_contribution_nb_density_energy.z + flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor * (flux_contribution_nb_momentum_x.z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor * (flux_contribution_nb_momentum_y.z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor * (flux_contribution_nb_momentum_z.z + flux_contribution_i_momentum_z.z);
            } else if (nb == -1) {
                flux_i_momentum.x += normal.x * pressure_i;
                flux_i_momentum.y += normal.y * pressure_i;
                flux_i_momentum.z += normal.z * pressure_i;
            } else if (nb == -2) {
                factor = 0.5f * normal.x;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
                flux_i_density_energy +=
                    factor * (ff_flux_contribution_density_energy[0].x + flux_contribution_i_density_energy.x);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0].x + flux_contribution_i_momentum_x.x);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0].x + flux_contribution_i_momentum_y.x);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0].x + flux_contribution_i_momentum_z.x);

                factor = 0.5f * normal.y;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
                flux_i_density_energy +=
                    factor * (ff_flux_contribution_density_energy[0].y + flux_contribution_i_density_energy.y);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0].y + flux_contribution_i_momentum_x.y);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0].y + flux_contribution_i_momentum_y.y);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0].y + flux_contribution_i_momentum_z.y);

                factor = 0.5f * normal.z;
                flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
                flux_i_density_energy +=
                    factor * (ff_flux_contribution_density_energy[0].z + flux_contribution_i_density_energy.z);
                flux_i_momentum.x += factor * (ff_flux_contribution_momentum_x[0].z + flux_contribution_i_momentum_x.z);
                flux_i_momentum.y += factor * (ff_flux_contribution_momentum_y[0].z + flux_contribution_i_momentum_y.z);
                flux_i_momentum.z += factor * (ff_flux_contribution_momentum_z[0].z + flux_contribution_i_momentum_z.z);
            }
        }

        fluxes[i + VAR_DENSITY * nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM + 0) * nelr] = flux_i_momentum.x;
        fluxes[i + (VAR_MOMENTUM + 1) * nelr] = flux_i_momentum.y;
        fluxes[i + (VAR_MOMENTUM + 2) * nelr] = flux_i_momentum.z;
        fluxes[i + VAR_DENSITY_ENERGY * nelr] = flux_i_density_energy;
    }
}

void time_step(int j, int nelr, const float* old_variables, float* variables, const float* step_factors,
               const float* fluxes) {
#pragma omp parallel for
    for (int i = 0; i < nelr; i++) {
        float factor = step_factors[i] / float(RK + 1 - j);

        variables[i + VAR_DENSITY * nelr] =
            old_variables[i + VAR_DENSITY * nelr] + factor * fluxes[i + VAR_DENSITY * nelr];
        variables[i + VAR_DENSITY_ENERGY * nelr] =
            old_variables[i + VAR_DENSITY_ENERGY * nelr] + factor * fluxes[i + VAR_DENSITY_ENERGY * nelr];
        variables[i + (VAR_MOMENTUM + 0) * nelr] =
            old_variables[i + (VAR_MOMENTUM + 0) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 0) * nelr];
        variables[i + (VAR_MOMENTUM + 1) * nelr] =
            old_variables[i + (VAR_MOMENTUM + 1) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 1) * nelr];
        variables[i + (VAR_MOMENTUM + 2) * nelr] =
            old_variables[i + (VAR_MOMENTUM + 2) * nelr] + factor * fluxes[i + (VAR_MOMENTUM + 2) * nelr];
    }
}

int main(int argc, char** argv) {
    printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n",
           BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

    if (argc < 2) {
        std::cout << "specify data file name and [device type] [device id]" << std::endl;
        return 0;
    }

    const char* data_file_name = argv[1];

    float* ff_variable = nullptr;
    float3* ff_flux_contribution_momentum_x = nullptr;
    float3* ff_flux_contribution_momentum_y = nullptr;
    float3* ff_flux_contribution_momentum_z = nullptr;
    float3* ff_flux_contribution_density_energy = nullptr;

    float* areas = nullptr;
    int* elements_surrounding_elements = nullptr;
    float* normals = nullptr;

    float* variables = nullptr;
    float* old_variables = nullptr;
    float* fluxes = nullptr;
    float* step_factors = nullptr;

    float h_ff_variable[NVAR];

    try {
        {
            const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

            h_ff_variable[VAR_DENSITY] = 1.4f;

            float ff_pressure = 1.0f;
            float ff_speed_of_sound = sqrtf(GAMMA * ff_pressure / h_ff_variable[VAR_DENSITY]);
            float ff_speed = ff_mach * ff_speed_of_sound;

            float3 ff_velocity;
            ff_velocity.x = ff_speed * cosf(angle_of_attack);
            ff_velocity.y = ff_speed * sinf(angle_of_attack);
            ff_velocity.z = 0.0f;

            h_ff_variable[VAR_MOMENTUM + 0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
            h_ff_variable[VAR_MOMENTUM + 1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
            h_ff_variable[VAR_MOMENTUM + 2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

            h_ff_variable[VAR_DENSITY_ENERGY] =
                h_ff_variable[VAR_DENSITY] * (0.5f * (ff_speed * ff_speed)) + (ff_pressure / float(GAMMA - 1.0f));

            float3 h_ff_momentum;
            h_ff_momentum.x = *(h_ff_variable + VAR_MOMENTUM + 0);
            h_ff_momentum.y = *(h_ff_variable + VAR_MOMENTUM + 1);
            h_ff_momentum.z = *(h_ff_variable + VAR_MOMENTUM + 2);

            float3 h_ff_flux_contribution_momentum_x;
            float3 h_ff_flux_contribution_momentum_y;
            float3 h_ff_flux_contribution_momentum_z;
            float3 h_ff_flux_contribution_density_energy;

            compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY],
                                      ff_pressure, ff_velocity, h_ff_flux_contribution_momentum_x,
                                      h_ff_flux_contribution_momentum_y, h_ff_flux_contribution_momentum_z,
                                      h_ff_flux_contribution_density_energy);

            ff_variable = alloc<float>(NVAR);
            ff_flux_contribution_momentum_x = alloc<float3>(1);
            ff_flux_contribution_momentum_y = alloc<float3>(1);
            ff_flux_contribution_momentum_z = alloc<float3>(1);
            ff_flux_contribution_density_energy = alloc<float3>(1);

            upload<float>(ff_variable, h_ff_variable, NVAR);
            upload<float3>(ff_flux_contribution_momentum_x, &h_ff_flux_contribution_momentum_x, 1);
            upload<float3>(ff_flux_contribution_momentum_y, &h_ff_flux_contribution_momentum_y, 1);
            upload<float3>(ff_flux_contribution_momentum_z, &h_ff_flux_contribution_momentum_z, 1);
            upload<float3>(ff_flux_contribution_density_energy, &h_ff_flux_contribution_density_energy, 1);
        }

        int nel;
        int nelr;

        {
            std::ifstream file(data_file_name);
            if (!file) throw std::string("can not find/open file!");

            file >> nel;
            nelr = block_length * ((nel / block_length) + std::min(1, nel % block_length));
            std::cout << "--cambine: nel=" << nel << ", nelr=" << nelr << std::endl;

            float* h_areas = new float[nelr];
            int* h_elements_surrounding_elements = new int[nelr * NNB];
            float* h_normals = new float[nelr * NDIM * NNB];

            for (int i = 0; i < nel; i++) {
                file >> h_areas[i];
                for (int j = 0; j < NNB; j++) {
                    file >> h_elements_surrounding_elements[i + j * nelr];
                    if (h_elements_surrounding_elements[i + j * nelr] < 0)
                        h_elements_surrounding_elements[i + j * nelr] = -1;
                    h_elements_surrounding_elements[i + j * nelr]--;

                    for (int k = 0; k < NDIM; k++) {
                        file >> h_normals[i + (j + k * NNB) * nelr];
                        h_normals[i + (j + k * NNB) * nelr] = -h_normals[i + (j + k * NNB) * nelr];
                    }
                }
            }

            int last = nel - 1;
            for (int i = nel; i < nelr; i++) {
                h_areas[i] = h_areas[last];
                for (int j = 0; j < NNB; j++) {
                    h_elements_surrounding_elements[i + j * nelr] =
                        h_elements_surrounding_elements[last + j * nelr];
                    for (int k = 0; k < NDIM; k++)
                        h_normals[last + (j + k * NNB) * nelr] = h_normals[last + (j + k * NNB) * nelr];
                }
            }

            areas = alloc<float>(nelr);
            upload<float>(areas, h_areas, nelr);

            elements_surrounding_elements = alloc<int>(nelr * NNB);
            upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr * NNB);

            normals = alloc<float>(nelr * NDIM * NNB);
            upload<float>(normals, h_normals, nelr * NDIM * NNB);

            delete[] h_areas;
            delete[] h_elements_surrounding_elements;
            delete[] h_normals;
        }

        variables = alloc<float>(nelr * NVAR);
        initialize_variables(nelr, variables, ff_variable);

        old_variables = alloc<float>(nelr * NVAR);
        fluxes = alloc<float>(nelr * NVAR);
        step_factors = alloc<float>(nelr);

        initialize_variables(nelr, old_variables, ff_variable);
        initialize_variables(nelr, fluxes, ff_variable);
        std::memset(step_factors, 0, sizeof(float) * nelr);

        std::cout << "Starting..." << std::endl;

        for (int i = 0; i < iterations; i++) {
            copy<float>(old_variables, variables, nelr * NVAR);

            compute_step_factor(nelr, variables, areas, step_factors);
            for (int j = 0; j < RK; j++) {
                compute_flux(nelr, elements_surrounding_elements, normals, variables, ff_variable, fluxes,
                             ff_flux_contribution_density_energy, ff_flux_contribution_momentum_x,
                             ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z);

                time_step(j, nelr, old_variables, variables, step_factors, fluxes);
            }
        }

        std::cout << "Saving solution..." << std::endl;
        dump(variables, nel, nelr);
        std::cout << "Saved solution..." << std::endl;
        std::cout << "Cleaning up..." << std::endl;

        dealloc(ff_variable);
        dealloc(ff_flux_contribution_momentum_x);
        dealloc(ff_flux_contribution_momentum_y);
        dealloc(ff_flux_contribution_momentum_z);
        dealloc(ff_flux_contribution_density_energy);
        dealloc(areas);
        dealloc(elements_surrounding_elements);
        dealloc(normals);
        dealloc(variables);
        dealloc(old_variables);
        dealloc(fluxes);
        dealloc(step_factors);

        ff_variable = nullptr;
        ff_flux_contribution_momentum_x = nullptr;
        ff_flux_contribution_momentum_y = nullptr;
        ff_flux_contribution_momentum_z = nullptr;
        ff_flux_contribution_density_energy = nullptr;
        areas = nullptr;
        elements_surrounding_elements = nullptr;
        normals = nullptr;
        variables = nullptr;
        old_variables = nullptr;
        fluxes = nullptr;
        step_factors = nullptr;

        std::cout << "Done..." << std::endl;
    } catch (std::string msg) {
        std::cout << "--cambine:( an exception catched in main body ->" << msg << std::endl;
        dealloc(ff_variable);
        dealloc(ff_flux_contribution_momentum_x);
        dealloc(ff_flux_contribution_momentum_y);
        dealloc(ff_flux_contribution_momentum_z);
        dealloc(ff_flux_contribution_density_energy);
        dealloc(areas);
        dealloc(elements_surrounding_elements);
        dealloc(normals);
        dealloc(variables);
        dealloc(old_variables);
        dealloc(fluxes);
        dealloc(step_factors);
    } catch (...) {
        std::cout << "--cambine:( unknow exceptions in main body..." << std::endl;
        dealloc(ff_variable);
        dealloc(ff_flux_contribution_momentum_x);
        dealloc(ff_flux_contribution_momentum_y);
        dealloc(ff_flux_contribution_momentum_z);
        dealloc(ff_flux_contribution_density_energy);
        dealloc(areas);
        dealloc(elements_surrounding_elements);
        dealloc(normals);
        dealloc(variables);
        dealloc(old_variables);
        dealloc(fluxes);
        dealloc(step_factors);
    }

    return 0;
}

#include <iostream>
