#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE_4 RD_WG_SIZE
#else
#define BLOCK_SIZE_4 192
#endif

#define NDIM 3
#define NNB 4

#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f

#if block_length > 128
#warning "the kernels may fail too launch on some systems if the block length is too large"
#endif

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)

typedef struct {
    float x;
    float y;
    float z;
} float3;

char device_type[3] = "";
int device_id = 0;
int platform_id = 0;

void _clCmdParams(int argc, char* argv[]) {
    for (int i = 0; i < argc; ++i) {
        if (!argv[i] || argv[i][0] != '-') continue;
        switch (argv[i][1]) {
            case 't':
                if (++i < argc) std::sscanf(argv[i], "%2s", device_type);
                break;
            case 'd':
                if (++i < argc) std::sscanf(argv[i], "%d", &device_id);
                break;
            case 'p':
                if (++i < argc) std::sscanf(argv[i], "%d", &platform_id);
                break;
            default:
                break;
        }
    }
}

