#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <sys/time.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
#define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define BLOCK_SIZE RD_WG_SIZE
#else
#define BLOCK_SIZE 16
#endif

#define STR_SIZE 256
#define EXPAND_RATE 2
#define MAX_PD (3.0e6)
#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP 0.5
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

const static float t_chip = 0.0005f;
const static float chip_height = 0.016f;
const static float chip_width = 0.016f;

static inline void fatal(const char *s) {
    fprintf(stderr, "Error: %s\n", s);
    exit(1);
}

void writeoutput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++) {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void readinput(float *vect, int grid_rows, int grid_cols, char *file) {
    int i, j;
    FILE *fp;
    char str[STR_SIZE];
    float val;

    if ((fp = fopen(file, "r")) == 0)
        fatal("The file was not opened");

    for (i = 0; i <= grid_rows - 1; i++)
        for (j = 0; j <= grid_cols - 1; j++) {
            if (fgets(str, STR_SIZE, fp) == NULL)
                fatal("Error reading file\n");
            if (feof(fp))
                fatal("not enough lines in file");

            if ((sscanf(str, "%f", &val) != 1))
                fatal("invalid file format");
            vect[i * grid_cols + j] = val;
        }

    fclose(fp);
}

int compute_tran_temp(float *MatrixPower, float *MatrixTemp[2], int col, int row,
                      int total_iterations, int num_iterations, int blockCols, int blockRows,
                      int borderCols, int borderRows, float *TempCPU, float *PowerCPU) {
    (void)blockCols;
    (void)blockRows;
    (void)borderCols;
    (void)borderRows;
    (void)TempCPU;
    (void)PowerCPU;

    float grid_height = chip_height / row;
    float grid_width = chip_width / col;

    float Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    float Rx = grid_width / (2.0f * K_SI * t_chip * grid_height);
    float Ry = grid_height / (2.0f * K_SI * t_chip * grid_width);
    float Rz = t_chip / (K_SI * grid_height * grid_width);

    float max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    float step = PRECISION / max_slope;

    const float amb_temp = 80.0f;
    float step_div_Cap = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    int src = 0, dst = 1;

    for (int t = 0; t < total_iterations; t += num_iterations) {
        int iter = MIN(num_iterations, total_iterations - t);
        for (int i = 0; i < iter; i++) {
#pragma omp parallel for collapse(2) schedule(static)
            for (int y = 0; y < row; y++) {
                for (int x = 0; x < col; x++) {
                    int idx = y * col + x;

                    int N = (y == 0) ? 0 : y - 1;
                    int S = (y == row - 1) ? row - 1 : y + 1;
                    int W = (x == 0) ? 0 : x - 1;
                    int E = (x == col - 1) ? col - 1 : x + 1;

                    float temp = MatrixTemp[src][idx];
                    MatrixTemp[dst][idx] =
                        temp + step_div_Cap *
                                   (MatrixPower[idx] +
                                    (MatrixTemp[src][S * col + x] + MatrixTemp[src][N * col + x] - 2.0f * temp) * Ry_1 +
                                    (MatrixTemp[src][y * col + E] + MatrixTemp[src][y * col + W] - 2.0f * temp) * Rx_1 +
                                    (amb_temp - temp) * Rz_1);
                }
            }
            src = 1 - src;
            dst = 1 - dst;
        }
    }

    return src;
}

void usage(int argc, char **argv) {
    (void)argc;
    fprintf(stderr, "Usage: %s <grid_rows/grid_cols> <pyramid_height> <sim_time> <temp_file> <power_file> <output_file> [-p platform_id] [-d device_id]\n", argv[0]);
