}

void computeTempCPU(float *pIn, float *tIn, float *tOut,
                    int nx, int ny, int nz, float Cap,
                    float Rx, float Ry, float Rz,
                    float dt, float amb_temp_local, int numiter)
{
    float ce, cw, cn, cs, ct, cb, cc;
    float stepDivCap = dt / Cap;
    ce = cw = stepDivCap / Rx;
    cn = cs = stepDivCap / Ry;
    ct = cb = stepDivCap / Rz;
    cc = 1.0f - (2.0f * ce + 2.0f * cn + 3.0f * ct);

    int c, w, e, n, s, b, t;
    int x, y, z;
    int i = 0;
    do {
        for (z = 0; z < nz; z++)
            for (y = 0; y < ny; y++)
                for (x = 0; x < nx; x++) {
                    c = x + y * nx + z * nx * ny;

                    w = (x == 0) ? c : c - 1;
                    e = (x == nx - 1) ? c : c + 1;
                    n = (y == 0) ? c : c - nx;
                    s = (y == ny - 1) ? c : c + nx;
                    b = (z == 0) ? c : c - nx * ny;
                    t = (z == nz - 1) ? c : c + nx * ny;

                    tOut[c] = tIn[c] * cc + tIn[n] * cn + tIn[s] * cs + tIn[e] * ce + tIn[w] * cw +
                              tIn[t] * ct + tIn[b] * cb + (dt / Cap) * pIn[c] + ct * amb_temp_local;
                }
        float *temp = tIn;
        tIn = tOut;
        tOut = temp;
        i++;
    } while (i < numiter);
}

float accuracy(float *arr1, float *arr2, int len)
{
    float err = 0.0f;
    int i;
    for (i = 0; i < len; i++)
        err += (arr1[i] - arr2[i]) * (arr1[i] - arr2[i]);

    return (float)sqrt(err / len);
}

void hotspotOpt1(float *p, float *tIn, float *tOut, float sdc,
                 int nx, int ny, int nz,
                 float ce, float cw,
                 float cn, float cs,
                 float ct, float cb,
                 float cc)
{
    float amb_temp_local = 80.0f;
    int xy = nx * ny;

    #pragma omp parallel for collapse(2) schedule(static)
    for (int j = 0; j < ny; ++j) {
        for (int i = 0; i < nx; ++i) {
            int c = i + j * nx;

            int W = (i == 0)    ? c : c - 1;
            int E = (i == nx-1) ? c : c + 1;
            int N = (j == 0)    ? c : c - nx;
            int S = (j == ny-1) ? c : c + nx;

            float temp1, temp2, temp3;
            temp1 = temp2 = tIn[c];
            temp3 = tIn[c + xy];

            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;

            c += xy; W += xy; E += xy; N += xy; S += xy;

            for (int k = 1; k < nz - 1; ++k) {
                temp1 = temp2;
                temp2 = temp3;
                temp3 = tIn[c + xy];

                tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                        + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;

                c += xy; W += xy; E += xy; N += xy; S += xy;
            }

            temp1 = temp2;
            temp2 = temp3;
            tOut[c] = cc * temp2 + cw * tIn[W] + ce * tIn[E] + cs * tIn[S]
                    + cn * tIn[N] + cb * temp1 + ct * temp3 + sdc * p[c] + ct * amb_temp_local;
        }
    }
}

