static int 
solver_omp(	fp **y,
			fp *x,
			int xmax,
			fp *params,
			fp *com,
			long long *timecopyin,
			long long *timecopykernel,
			long long *timecopyout)
{
	fp err_exponent;
	int error;
	int outside;
	fp h;
	fp h_init;
	fp tolerance;
	int xmin;

	fp scale_min;
	fp scale_fina;
