	err_exponent = 1.0 / 7.0;
	h_init = 1;
	h = h_init;
	xmin = 0;
	tolerance = 10 / (fp)(xmax-xmin);

	x[0] = 0;

	if (xmax < xmin || h <= 0.0){
		free(err); free(scale); free(yy);
		return -2;
	}

	if (xmax == xmin){
		free(err); free(scale); free(yy);
		return 0;
	}

	if (h > (xmax - xmin) ) {
		h = (fp)xmax - (fp)xmin;
	}

	printf("Time Steps: ");
	fflush(0);

	for(k=1; k<=xmax; k++) {

		x[k] = k-1;
		h = h_init;
		scale_fina = 1.0;

		for (j = 0; j < ATTEMPTS; j++) {

			error = 0;
			outside = 0;
			scale_min = MAX_SCALE_FACTOR;

			embedded_fehlberg_7_8(	x[k],
									h,
									y[k-1],
									y[k],
									err,
									params,
									com,
									timecopyin,
									timecopykernel,
									timecopyout);

			for(i=0; i<EQUATIONS; i++){
				if(err[i] > 0){
					error = 1;
				}
			}
			if (error != 1) {
				scale_fina = MAX_SCALE_FACTOR;
				break;
			}

			for(i=0; i<EQUATIONS; i++){
				if(y[k-1][i] == 0.0){
					yy[i] = tolerance;
				}
				else{
					yy[i] = fabs(y[k-1][i]);
