static inline void compute_tile(const int *reference_d, int *input_itemsets_d, int cols, int penalty, int base, int b_index_x, int b_index_y) {
    int input_itemsets_l[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int reference_l[BLOCK_SIZE * BLOCK_SIZE];

#define SCORE(i, j) input_itemsets_l[(j) + (i) * (BLOCK_SIZE + 1)]
#define REF(i, j) reference_l[(j) + (i) * BLOCK_SIZE]

    const int tile_base = base + cols * BLOCK_SIZE * b_index_y + BLOCK_SIZE * b_index_x;

    SCORE(0, 0) = input_itemsets_d[tile_base];

    for (int ty = 0; ty < BLOCK_SIZE; ty++) {
        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            REF(ty, tx) = reference_d[tile_base + (cols + 1) + tx + cols * ty];
        }
    }

    for (int tx = 0; tx < BLOCK_SIZE; tx++) {
        SCORE(tx + 1, 0) = input_itemsets_d[tile_base + cols * (tx + 1)];
        SCORE(0, tx + 1) = input_itemsets_d[tile_base + 1 + tx];
    }

    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            SCORE(i, j) = maximum(SCORE(i - 1, j - 1) + REF(i - 1, j - 1),
                                  SCORE(i, j - 1) - penalty,
                                  SCORE(i - 1, j) - penalty);
        }
    }

    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            input_itemsets_d[tile_base + i * cols + j] = SCORE(i, j);
        }
    }

#undef SCORE
#undef REF
}

static void nw_kernel1_omp(const int *reference_d, int *input_itemsets_d, int cols, int penalty, int blk, int block_width, int worksize, int offset_r, int offset_c) {
    (void)block_width;
    (void)worksize;
    int base = offset_r * cols + offset_c;

#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx;
        int b_index_y = blk - 1 - bx;
        compute_tile(reference_d, input_itemsets_d, cols, penalty, base, b_index_x, b_index_y);
    }
}

static void nw_kernel2_omp(const int *reference_d, int *input_itemsets_d, int cols, int penalty, int blk, int block_width, int worksize, int offset_r, int offset_c) {
    (void)worksize;
    int base = offset_r * cols + offset_c;

#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < blk; bx++) {
        int b_index_x = bx + block_width - blk;
        int b_index_y = block_width - bx - 1;
        compute_tile(reference_d, input_itemsets_d, cols, penalty, base, b_index_x, b_index_y);
    }
}

