static inline void process_block(int *reference, int *input_itemsets, int cols, int penalty,
                                 int b_index_x, int b_index_y, int offset_r, int offset_c) {
    int score[(BLOCK_SIZE + 1) * (BLOCK_SIZE + 1)];
    int row_base = offset_r + b_index_y * BLOCK_SIZE;
    int col_base = offset_c + b_index_x * BLOCK_SIZE;

#define SCORE_LOCAL(i, j) score[(j) + (i) * (BLOCK_SIZE + 1)]

    SCORE_LOCAL(0, 0) = input_itemsets[row_base * cols + col_base];
    for (int i = 1; i <= BLOCK_SIZE; i++) {
        SCORE_LOCAL(i, 0) = input_itemsets[(row_base + i) * cols + col_base];
    }
    for (int j = 1; j <= BLOCK_SIZE; j++) {
        SCORE_LOCAL(0, j) = input_itemsets[row_base * cols + (col_base + j)];
    }

    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            int ref = reference[(row_base + i) * cols + (col_base + j)];
            SCORE_LOCAL(i, j) = maximum(SCORE_LOCAL(i - 1, j - 1) + ref,
                                        SCORE_LOCAL(i, j - 1) - penalty,
                                        SCORE_LOCAL(i - 1, j) - penalty);
        }
    }

    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            input_itemsets[(row_base + i) * cols + (col_base + j)] = SCORE_LOCAL(i, j);
        }
    }

#undef SCORE_LOCAL
}

