static void dynproc_kernel_omp(
    int iteration,
    int* gpuWall,
    int* gpuSrc,
    int* gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO_VAL,
    int* outputBuffer,
    int BLOCK_SIZE)
{
    int small_block_cols = BLOCK_SIZE - (iteration * HALO_VAL * 2);
    if (small_block_cols <= 0) return;

    int num_groups = ((cols - 1 + border) / small_block_cols) + 1;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < num_groups; bx++) {
        int* prev = new int[BLOCK_SIZE];
        int* result_local = new int[BLOCK_SIZE];
        bool* computed = new bool[BLOCK_SIZE];

        int blkX = (small_block_cols * bx) - border;
        int blkXmax = blkX + BLOCK_SIZE - 1;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX + tx;
            if (IN_RANGE(xidx, 0, cols - 1)) {
                prev[tx] = gpuSrc[xidx];
            }
        }

        for (int i = 0; i < iteration; i++) {
            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                computed[tx] = false;

                int xidx = blkX + tx;
                int W = tx - 1;
                int E = tx + 1;

                W = (W < validXmin) ? validXmin : W;
                E = (E > validXmax) ? validXmax : E;

                bool isValid = IN_RANGE(tx, validXmin, validXmax);

                if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
                    computed[tx] = true;
                    int left = prev[W];
                    int up = prev[tx];
                    int right = prev[E];
                    int shortest = MIN(left, up);
                    shortest = MIN(shortest, right);

                    int index = cols * (startStep + i) + xidx;
                    result_local[tx] = shortest + gpuWall[index];

