                            outputBuffer[bufIndex] = 1;
                        }
                    }
                }
            }

            if (i == iteration - 1) {
                break;
            }

            for (int tx = 0; tx < BLOCK_SIZE; tx++) {
                if (computed[tx]) {
                    prev[tx] = result_local[tx];
                }
            }
        }

        for (int tx = 0; tx < BLOCK_SIZE; tx++) {
            if (computed[tx]) {
                int xidx = blkX + tx;
                gpuResults[xidx] = result_local[tx];
            }
        }

        delete[] prev;
        delete[] result_local;
        delete[] computed;
    }
}

