void kernel_gpu_opencl_wrapper(fp* image,
                               int Nr,
                               int Nc,
                               long Ne,
                               int niter,
                               fp lambda,
                               long NeROI,
                               int* iN,
                               int* iS,
                               int* jE,
                               int* jW,
                               int iter,
                               int mem_size_i,
                               int mem_size_j) {
    (void)iter;
    (void)mem_size_i;
    (void)mem_size_j;

    printf("Platform: OpenMP\n");
    printf("Device: CPU\n");

    int blocks_x = (int)(Ne / NUMBER_THREADS);
    if (Ne % NUMBER_THREADS != 0) blocks_x = blocks_x + 1;
    size_t global_work_size = (size_t)blocks_x * NUMBER_THREADS;
    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           (int)(global_work_size / NUMBER_THREADS), NUMBER_THREADS);

    fp* d_I = image;
    fp* d_dN = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dS = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dW = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_dE = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_c  = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums  = (fp*)malloc(sizeof(fp) * Ne);
    fp* d_sums2 = (fp*)malloc(sizeof(fp) * Ne);

    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ei++) {
        d_I[ei] = (fp)exp(d_I[ei] / (fp)255.0);
    }

    printf("Iterations Progress: hidden");

    for (iter = 0; iter < niter; iter++) {
        fflush(NULL);

        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ei++) {
            d_sums[ei] = d_I[ei];
            d_sums2[ei] = d_I[ei] * d_I[ei];
        }

        fp total = 0.0f;
        fp total2 = 0.0f;
        #pragma omp parallel for reduction(+:total,total2)
        for (long ei = 0; ei < Ne; ei++) {
            total += d_sums[ei];
            total2 += d_sums2[ei];
        }

        fp meanROI = total / (fp)(NeROI);
        fp meanROI2 = meanROI * meanROI;
        fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
        fp q0sqr = varROI / meanROI2;

        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ei++) {
            int row = (int)((ei + 1) % Nr - 1);
            int col = (int)((ei + 1) / Nr + 1 - 1);
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_Jc = d_I[ei];

            fp d_dN_loc = d_I[iN[row] + Nr * col] - d_Jc;
            fp d_dS_loc = d_I[iS[row] + Nr * col] - d_Jc;
            fp d_dW_loc = d_I[row + Nr * jW[col]] - d_Jc;
            fp d_dE_loc = d_I[row + Nr * jE[col]] - d_Jc;

            fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
            fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            fp d_num = (fp)(0.5) * d_G2 - (fp)(1.0 / 16.0) * (d_L * d_L);
            fp d_den = (fp)1.0 + (fp)0.25 * d_L;
            fp d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - q0sqr) / (q0sqr * ((fp)1.0 + q0sqr));
            fp d_c_loc = (fp)1.0 / ((fp)1.0 + d_den);

            if (d_c_loc < 0) d_c_loc = 0;
            else if (d_c_loc > 1) d_c_loc = 1;

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }

        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ei++) {
            int row = (int)((ei + 1) % Nr - 1);
            int col = (int)((ei + 1) / Nr + 1 - 1);
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_cN = d_c[ei];
            fp d_cS = d_c[iS[row] + Nr * col];
            fp d_cW = d_c[ei];
            fp d_cE = d_c[row + Nr * jE[col]];

            fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

            d_I[ei] = d_I[ei] + (fp)0.25 * lambda * d_D;
        }
    }

    printf("\n");

    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ei++) {
        d_I[ei] = (fp)(log(d_I[ei]) * 255.0);
    }

    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
    free(d_sums);
    free(d_sums2);
}

