        fp meanROI = total / (fp)(NeROI);
        fp meanROI2 = meanROI * meanROI;
        fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
        fp q0sqr = varROI / meanROI2;

        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ei++) {
            int row = (int)((ei + 1) % Nr) - 1;
            int col = (int)((ei + 1) / Nr) + 1 - 1;
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_Jc = d_I[ei];

            fp d_dN_loc = d_I[d_iN[row] + Nr * col] - d_Jc;
            fp d_dS_loc = d_I[d_iS[row] + Nr * col] - d_Jc;
            fp d_dW_loc = d_I[row + Nr * d_jW[col]] - d_Jc;
            fp d_dE_loc = d_I[row + Nr * d_jE[col]] - d_Jc;

            fp d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc + d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) / (d_Jc * d_Jc);
            fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

            fp d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
            fp d_den = 1.0f + (0.25f * d_L);
            fp d_qsqr = d_num / (d_den * d_den);

            d_den = (d_qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
            fp d_c_loc = 1.0f / (1.0f + d_den);

            if (d_c_loc < 0.0f) {
                d_c_loc = 0.0f;
            } else if (d_c_loc > 1.0f) {
                d_c_loc = 1.0f;
            }

            d_dN[ei] = d_dN_loc;
            d_dS[ei] = d_dS_loc;
            d_dW[ei] = d_dW_loc;
            d_dE[ei] = d_dE_loc;
            d_c[ei] = d_c_loc;
        }

        #pragma omp parallel for
        for (long ei = 0; ei < Ne; ei++) {
            int row = (int)((ei + 1) % Nr) - 1;
            int col = (int)((ei + 1) / Nr) + 1 - 1;
            if ((ei + 1) % Nr == 0) {
                row = Nr - 1;
                col = col - 1;
            }

            fp d_cN = d_c[ei];
            fp d_cS = d_c[d_iS[row] + Nr * col];
            fp d_cW = d_c[ei];
            fp d_cE = d_c[row + Nr * d_jE[col]];

            fp d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];
            d_I[ei] = d_I[ei] + 0.25f * lambda * d_D;
        }
    }

    printf("\n");

    #pragma omp parallel for
    for (long ei = 0; ei < Ne; ei++) {
        d_I[ei] = logf(d_I[ei]) * 255.0f;
    }

    memcpy(image, d_I, mem_size);

    free(d_I);
    free(d_iN);
    free(d_iS);
    free(d_jE);
    free(d_jW);
    free(d_dN);
    free(d_dS);
    free(d_dW);
    free(d_dE);
    free(d_c);
    free(d_sums);
    free(d_sums2);
}

