int platform_id = 0;
int device_id = 0;

static inline void tvsub(const struct timeval *t1, const struct timeval *t0, struct timeval *td) {
  td->tv_sec = t1->tv_sec - t0->tv_sec;
  td->tv_usec = t1->tv_usec - t0->tv_usec;
  if (td->tv_usec < 0) {
    td->tv_sec--;
    td->tv_usec += 1000000;
  }
}

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

void _clCmdParams(int argc, char *argv[]) {
  for (int i = 0; i < argc; ++i) {
    if (argv[i] == nullptr || argv[i][0] != '-' || argv[i][1] == '\0') continue;
    switch (argv[i][1]) {
      case 'p':
        if (++i < argc) sscanf(argv[i], "%d", &platform_id);
        break;
      case 'd':
        if (++i < argc) sscanf(argv[i], "%d", &device_id);
        break;
      default:
        break;
    }
  }
}
