void inttofile(int data, char *filename) {
  FILE *fp = fopen(filename, "w");
  fprintf(fp, "%d ", data);
  fclose(fp);
}

int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  return equal ? 1 : 0;
}

static int floatcomp(const void *i, const void *j) {
  float a = *(float *)(i);
  float b = *(float *)(j);
  if (a > b) return 1;
  if (a < b) return -1;
  return 0;
}

void shuffle(Points *points) {
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
}

void intshuffle(int *intarray, int length) {
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
}

float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float d = p1.coord[i] - p2.coord[i];
    result += d * d;
  }
  return result;
}

void quit(char *message) {
  printf("%s\n", message);
  exit(1);
}

