float pgain(long x, Points *points, float z, long int *numcenters, int kmax, bool *is_center_arr,
            int *center_table_arr, char *switch_membership_arr, double *serial_t,
            double *, double *, double *, double *) {
  double t0 = gettime();
  float gl_cost = 0.0f;
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;
  kmax++;

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) center_table_arr[i] = count++;
  }

  static float *work_mem_h = nullptr;
  static float *gl_lower = nullptr;
  static int work_cap = 0;
  int needed = num * (K + 1);
  if (needed > work_cap) {
    free(work_mem_h);
    work_mem_h = (float *)malloc(sizeof(float) * needed);
    work_cap = needed;
  }
  free(gl_lower);
  gl_lower = (float *)malloc(sizeof(float) * (K + 1));

  memset(switch_membership_arr, 0, num * sizeof(char));
  memset(work_mem_h, 0, needed * sizeof(float));

  float *coord_s = (float *)malloc(sizeof(float) * dim);
  for (int i = 0; i < dim; i++) coord_s[i] = points->p[x].coord[i];

#pragma omp parallel for schedule(static)
  for (int thread_id = 0; thread_id < num; thread_id++) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float diff = points->p[thread_id].coord[i] - coord_s[i];
      x_cost += diff * diff;
    }
    x_cost *= points->p[thread_id].weight;
    float current_cost = points->p[thread_id].cost;
    int base = thread_id * (K + 1);

    if (x_cost < current_cost) {
      switch_membership_arr[thread_id] = '1';
      work_mem_h[base + K] = x_cost - current_cost;
    } else {
      int assign = (int)points->p[thread_id].assign;
      int addr = base + center_table_arr[assign];
#pragma omp atomic
      work_mem_h[addr] += current_cost - x_cost;
    }
  }

  free(coord_s);

  int numclose = 0;
  gl_cost = z;

  for (int i = 0; i < num; i++) {
    if (is_center_arr[i]) {
      float low = z;
      for (int j = 0; j < num; j++) {
        low += work_mem_h[j * (K + 1) + center_table_arr[i]];
      }
      gl_lower[center_table_arr[i]] = low;
      if (low > 0) {
        numclose++;
        work_mem_h[i * (K + 1) + K] -= low;
      }
    }
    gl_cost += work_mem_h[i * (K + 1) + K];
  }

  if (gl_cost < 0) {
#pragma omp parallel for schedule(static)
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table_arr[points->p[i].assign]] > 0;
      if ((switch_membership_arr[i] == '1') || close_center) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center_arr[i] && gl_lower[center_table_arr[i]] > 0) is_center_arr[i] = false;
    }
    is_center_arr[x] = true;
    *numcenters = *numcenters + 1 - numclose;
  } else {
    gl_cost = 0.0f;
  }

  if (serial_t) *serial_t += (gettime() - t0);
  free(gl_lower);
  gl_lower = nullptr;
  return -gl_cost;
}

float pspeedy(Points *points, float z, long *kcenter, int, pthread_barrier_t *) {
  cnt_speedy++;
  static float totalcost = 0.0f;

#pragma omp parallel for schedule(static)
  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;
  for (int i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        float nc = distance * points->p[k].weight;
        if (nc < points->p[k].cost) {
          points->p[k].cost = nc;
          points->p[k].assign = i;
        }
      }
    }
  }

  float mytotal = 0.0f;
#pragma omp parallel for reduction(+ : mytotal) schedule(static)
  for (long k = 0; k < points->num; k++) mytotal += points->p[k].cost;

  totalcost = z * (*kcenter) + mytotal;
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible, float z, long *k, int kmax, float cost,
          long iter, float e, int pid, pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;
  float change = cost;

  while (change / cost > 1.0f * e) {
    change = 0.0f;
    intshuffle(feasible, numfeasible);

    for (long i = 0; i < iter; i++) {
      long x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table, switch_membership,
                      &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }
    cost -= change;
  }
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int, pthread_barrier_t *) {
  int numfeasible = points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  long k1 = 0;
  long k2 = numfeasible;

  if (numfeasible == points->num) {
    for (int i = k1; i < k2; i++) (*feasible)[i] = i;
    return numfeasible;
  }

  float *accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  for (int i = 1; i < points->num; i++) accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  float totalweight = accumweight[points->num - 1];

  for (int i = k1; i < k2; i++) {
    float w = (lrand48() / (float)INT_MAX) * totalweight;
    int l = 0, r = points->num - 1, k;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) r = k;
      else l = k;
    }
    (*feasible)[i] = r;
  }
  free(accumweight);
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal, int pid, pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;

  int i;
  float cost, lastcost;
  float hiz, loz, z;
  long k;
  int *feasible = nullptr;
  int numfeasible = 0;

  hiz = loz = 0.0f;
  for (long kk = 0; kk < points->num; kk++) {
    hiz += dist(points->p[kk], points->p[0], points->dim) * points->p[kk].weight;
  }

  loz = 0.0f;
  z = (hiz + loz) / 2.0f;

  if (points->num <= kmax) {
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    *kfinal = points->num;
    return 0.0f;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k, 0, nullptr);
  i = 0;

  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, 0, nullptr);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k, 0, nullptr);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, kmin, 0, nullptr);
  for (int ii = 0; ii < points->num; ii++) is_center[points->p[ii].assign] = true;

  while (1) {
    lastcost = cost;
    cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
               (long)(ITER * kmax * log((float)kmax)), 0.1f, 0, nullptr);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) || ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
                 (long)(ITER * kmax * log((float)kmax)), 0.001f, 0, nullptr);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999) * hiz))) break;
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  for (long i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      float relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (long ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0 - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));
  for (long i = 0; i < points->num; i++) is_a_median[points->p[i].assign] = 1;

  long k = centers->num;
  for (long i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }
  centers->num = k;
  free(is_a_median);
}

void *localSearchSub(void *arg_) {
  pkmedian_arg_t *arg = (pkmedian_arg_t *)arg_;
  pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
  return NULL;
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
  pkmedian(points, kmin, kmax, kfinal, 0, nullptr);
}

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) is_a_median[centers->p[i].assign] = 1;

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) fprintf(fp, "%lf ", centers->p[i].coord[k]);
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream *stream, long kmin, long kmax, int dim, long chunksize, long centersize, char *outfile) {
  float *block = (float *)malloc(chunksize * dim * sizeof(float));
  float *centerBlock = (float *)malloc(centersize * dim * sizeof(float));
  long *centerIDs = (long *)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) points.p[i].coord = &block[i * dim];

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize * sizeof(Point));
  centers.num = 0;
  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %lu points\n", numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) points.p[i].weight = 1.0;

    switch_membership = (char *)malloc(points.num * sizeof(char));
    is_center = (bool *)calloc(points.num, sizeof(bool));
    center_table = (int *)malloc(points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);

    if (stream->feof()) break;
  }

  switch_membership = (char *)malloc(centers.num * sizeof(char));
  is_center = (bool *)calloc(centers.num, sizeof(bool));
  center_table = (int *)malloc(centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(points.p);
  free(centers.p);
  free(block);
  free(centerBlock);
  free(centerIDs);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif

  if (argc < 11) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n", argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "  platform:    Platform id\n");
    fprintf(stderr, "  device:      Device id\n\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }

  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);
  if (nproc < 1) nproc = 1;
  omp_set_num_threads(nproc);
  _clCmdParams(argc, argv);

  try {
    _clInit(platform_id, device_id);
  } catch (...) {
    std::cout << "exception caught in main function->init failed" << std::endl;
    return -1;
  }

  srand48(SEED);
  PStream *stream;
  if (n > 0) stream = new SimStream(n);
  else stream = new FileStream(infilename);

  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  cnt_speedy = 0;

  std::cout << "before sc" << std::endl;
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
  std::cout << "after sc" << std::endl;

  freeDevMem();
  _clRelease();
  _clStatistics();

  delete stream;
  delete[] outfilename;
  delete[] infilename;

  return 0;
}

