#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define CACHE_LINE 512

typedef struct {
  float weight;
  float *coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t {
  Points *points;
  long kmin;
  long kmax;
  long *kfinal;
  int pid;
  pthread_barrier_t *barrier;
};

class PStream {
public:
  virtual size_t read(float *dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) : n(n_) {}
  size_t read(float *dest, int dim, int num) override {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() override { return 0; }
  int feof() override { return n <= 0; }
  ~SimStream() override {}
private:
  long n;
};

class FileStream : public PStream {
public:
  FileStream(char *filename) {
    fp = fopen(filename, "rb");
    if (fp == NULL) {
      fprintf(stderr, "error opening file %s\n.", filename);
      exit(1);
    }
  }
  size_t read(float *dest, int dim, int num) override {
    return std::fread(dest, sizeof(float) * dim, num, fp);
  }
  int ferror() override { return std::ferror(fp); }
  int feof() override { return std::feof(fp); }
  ~FileStream() override {
    printf("closing file stream\n");
    fclose(fp);
  }
private:
  FILE *fp;
};

double gettime() {
  struct timeval t;
  gettimeofday(&t, NULL);
  return t.tv_sec + t.tv_usec * 1e-6;
}

#ifdef TIMING
