int isIdentical(float *i, float *j, int D) {
  int a = 0;
  int equal = 1;
  while (equal && a < D) {
    if (i[a] != j[a]) equal = 0;
    else a++;
  }
  return equal ? 1 : 0;
}

static int floatcomp(const void *i, const void *j) {
  float a = *(float *)(i);
  float b = *(float *)(j);
  if (a > b) return 1;
  if (a < b) return -1;
  return 0;
}

void shuffle(Points *points) {
  long i, j;
  Point temp;
  for (i = 0; i < points->num - 1; i++) {
    j = (lrand48() % (points->num - i)) + i;
    temp = points->p[i];
    points->p[i] = points->p[j];
    points->p[j] = temp;
  }
}

void intshuffle(int *intarray, int length) {
  long i, j;
  int temp;
  for (i = 0; i < length; i++) {
    j = (lrand48() % (length - i)) + i;
    temp = intarray[i];
    intarray[i] = intarray[j];
    intarray[j] = temp;
  }
}

float dist(Point p1, Point p2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float d = p1.coord[i] - p2.coord[i];
    result += d * d;
  }
  return result;
}

float pgain(long x, Points *points, float z, long int *numcenters, int kmax,
            bool *is_center, int *center_table, char *switch_membership,
            double *serial_t, double *, double *, double *, double *) {
  (void)kmax;
  double t0 = gettime();
  int K = (int)(*numcenters);
  int num = (int)points->num;
  int dim = points->dim;

  int count = 0;
  for (int i = 0; i < num; i++) {
    if (is_center[i]) center_table[i] = count++;
  }

  std::vector<float> work_mem((size_t)num * (K + 1), 0.0f);
  std::vector<float> gl_lower(std::max(1, K), 0.0f);
  memset(switch_membership, 0, num * sizeof(char));

#pragma omp parallel for schedule(static)
  for (int tid = 0; tid < num; tid++) {
    float x_cost = 0.0f;
    for (int i = 0; i < dim; i++) {
      float d = points->p[tid].coord[i] - points->p[x].coord[i];
      x_cost += d * d;
    }
    x_cost *= points->p[tid].weight;
    float current_cost = points->p[tid].cost;
    int base = tid * (K + 1);

    if (x_cost < current_cost) {
      switch_membership[tid] = '1';
      work_mem[base + K] = x_cost - current_cost;
    } else {
      int assign = (int)points->p[tid].assign;
      int addr = base + center_table[assign];
      work_mem[addr] += current_cost - x_cost;
    }
  }

  int numclose = 0;
  float gl_cost = z;

  for (int i = 0; i < num; i++) {
    if (is_center[i]) {
      float low = z;
      int ci = center_table[i];
      for (int j = 0; j < num; j++) {
        low += work_mem[j * (K + 1) + ci];
      }
      gl_lower[ci] = low;
      if (low > 0) {
        numclose++;
        work_mem[i * (K + 1) + K] -= low;
      }
    }
    gl_cost += work_mem[i * (K + 1) + K];
  }

  if (gl_cost < 0) {
#pragma omp parallel for schedule(static)
    for (int i = 0; i < num; i++) {
      bool close_center = gl_lower[center_table[points->p[i].assign]] > 0;
      if ((switch_membership[i] == '1') || close_center) {
        points->p[i].cost = points->p[i].weight * dist(points->p[i], points->p[x], points->dim);
        points->p[i].assign = x;
      }
    }

    for (int i = 0; i < num; i++) {
      if (is_center[i] && gl_lower[center_table[i]] > 0) is_center[i] = false;
    }
    is_center[x] = true;
    *numcenters = *numcenters + 1 - numclose;
  } else {
    gl_cost = 0;
  }

  if (serial_t) *serial_t += (gettime() - t0);
  return -gl_cost;
}

float pspeedy(Points *points, float z, long *kcenter, int, pthread_barrier_t *) {
  cnt_speedy++;

#pragma omp parallel for schedule(static)
  for (long k = 0; k < points->num; k++) {
    float distance = dist(points->p[k], points->p[0], points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign = 0;
  }

  *kcenter = 1;
  for (long i = 1; i < points->num; i++) {
    bool to_open = ((float)lrand48() / (float)INT_MAX) < (points->p[i].cost / z);
    if (to_open) {
      (*kcenter)++;
#pragma omp parallel for schedule(static)
      for (long k = 0; k < points->num; k++) {
        float distance = dist(points->p[i], points->p[k], points->dim);
        float nc = distance * points->p[k].weight;
        if (nc < points->p[k].cost) {
          points->p[k].cost = nc;
          points->p[k].assign = i;
        }
      }
    }
  }

  float totalcost = z * (*kcenter);
  float sum = 0.0f;
#pragma omp parallel for reduction(+ : sum) schedule(static)
  for (long k = 0; k < points->num; k++) {
    sum += points->p[k].cost;
  }
  totalcost += sum;
  return totalcost;
}

float pFL(Points *points, int *feasible, int numfeasible, float z, long *k, int kmax,
          float cost, long iter, float e, int pid, pthread_barrier_t *barrier) {
  (void)kmax;
  (void)pid;
  (void)barrier;
  float change = cost;

  while (change / cost > 1.0f * e) {
    change = 0.0f;
    intshuffle(feasible, numfeasible);
    for (long i = 0; i < iter; i++) {
      long x = i % numfeasible;
      change += pgain(feasible[x], points, z, k, kmax, is_center, center_table,
                      switch_membership, &serial, &cpu_gpu_memcpy, &memcpy_back, &gpu_malloc, &kernel);
    }
    cost -= change;
  }
  return cost;
}

int selectfeasible_fast(Points *points, int **feasible, int kmin, int, pthread_barrier_t *) {
  int numfeasible = points->num;
  if (numfeasible > (ITER * kmin * log((float)kmin)))
    numfeasible = (int)(ITER * kmin * log((float)kmin));
  *feasible = (int *)malloc(numfeasible * sizeof(int));

  long k1 = 0;
  long k2 = numfeasible;

  if (numfeasible == points->num) {
    for (int i = k1; i < k2; i++) (*feasible)[i] = i;
    return numfeasible;
  }

  float *accumweight = (float *)malloc(sizeof(float) * points->num);
  accumweight[0] = points->p[0].weight;
  for (int i = 1; i < points->num; i++) {
    accumweight[i] = accumweight[i - 1] + points->p[i].weight;
  }
  float totalweight = accumweight[points->num - 1];

  for (int i = k1; i < k2; i++) {
    float w = (lrand48() / (float)INT_MAX) * totalweight;
    int l = 0, r = points->num - 1, k;
    if (accumweight[0] > w) {
      (*feasible)[i] = 0;
      continue;
    }
    while (l + 1 < r) {
      k = (l + r) / 2;
      if (accumweight[k] > w) r = k;
      else l = k;
    }
    (*feasible)[i] = r;
  }

  free(accumweight);
  return numfeasible;
}

float pkmedian(Points *points, long kmin, long kmax, long *kfinal, int pid, pthread_barrier_t *barrier) {
  (void)pid;
  (void)barrier;
  float cost;
  float lastcost;
  float hiz, loz, z;
  long k;
  int *feasible = nullptr;
  int numfeasible;

  hiz = loz = 0.0f;
  long numberOfPoints = points->num;
  long ptDimension = points->dim;

#ifdef PRINTINFO
  printf("Starting Kmedian procedure\n");
  printf("%li points in %li dimensions\n", numberOfPoints, ptDimension);
#endif

  float myhiz = 0.0f;
#pragma omp parallel for reduction(+ : myhiz) schedule(static)
  for (long kk = 0; kk < points->num; kk++) {
    myhiz += dist(points->p[kk], points->p[0], ptDimension) * points->p[kk].weight;
  }
  hiz = myhiz;

  loz = 0.0f;
  z = (hiz + loz) / 2.0f;

  if (points->num <= kmax) {
#pragma omp parallel for schedule(static)
    for (long kk = 0; kk < points->num; kk++) {
      points->p[kk].assign = kk;
      points->p[kk].cost = 0;
    }
    *kfinal = points->num;
    return 0.0f;
  }

  shuffle(points);
  cost = pspeedy(points, z, &k, 0, nullptr);
  int i = 0;
  while ((k < kmin) && (i < SP)) {
    cost = pspeedy(points, z, &k, 0, nullptr);
    i++;
  }

  while (k < kmin) {
    if (i >= SP) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      i = 0;
    }
    shuffle(points);
    cost = pspeedy(points, z, &k, 0, nullptr);
    i++;
  }

  numfeasible = selectfeasible_fast(points, &feasible, kmin, 0, nullptr);
  for (int ii = 0; ii < points->num; ii++) {
    is_center[points->p[ii].assign] = true;
  }

  while (1) {
    lastcost = cost;
    cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
               (long)(ITER * kmax * log((float)kmax)), 0.1f, 0, nullptr);

    if (((k <= (1.1) * kmax) && (k >= (0.9) * kmin)) || ((k <= kmax + 2) && (k >= kmin - 2))) {
      cost = pFL(points, feasible, numfeasible, z, &k, kmax, cost,
                 (long)(ITER * kmax * log((float)kmax)), 0.001f, 0, nullptr);
    }

    if (k > kmax) {
      loz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - loz) * k;
    }
    if (k < kmin) {
      hiz = z;
      z = (hiz + loz) / 2.0f;
      cost += (z - hiz) * k;
    }

    if (((k <= kmax) && (k >= kmin)) || ((loz >= (0.999f) * hiz))) {
      break;
    }

    if (fabs(lastcost - cost) < 1e-12f) break;
  }

  free(feasible);
  *kfinal = k;
  return cost;
}

int contcenters(Points *points) {
  for (long i = 0; i < points->num; i++) {
    if (points->p[i].assign != i) {
      float relweight = points->p[points->p[i].assign].weight + points->p[i].weight;
      relweight = points->p[i].weight / relweight;
      for (long ii = 0; ii < points->dim; ii++) {
        points->p[points->p[i].assign].coord[ii] *= 1.0f - relweight;
        points->p[points->p[i].assign].coord[ii] += points->p[i].coord[ii] * relweight;
      }
      points->p[points->p[i].assign].weight += points->p[i].weight;
    }
  }
  return 0;
}

void copycenters(Points *points, Points *centers, long *centerIDs, long offset) {
  bool *is_a_median = (bool *)calloc(points->num, sizeof(bool));
  for (long i = 0; i < points->num; i++) is_a_median[points->p[i].assign] = 1;

  long k = centers->num;
  for (long i = 0; i < points->num; i++) {
    if (is_a_median[i]) {
      memcpy(centers->p[k].coord, points->p[i].coord, points->dim * sizeof(float));
      centers->p[k].weight = points->p[i].weight;
      centerIDs[k] = i + offset;
      k++;
    }
  }
  centers->num = k;
  free(is_a_median);
}

void *localSearchSub(void *arg_) {
  pkmedian_arg_t *arg = (pkmedian_arg_t *)arg_;
  pkmedian(arg->points, arg->kmin, arg->kmax, arg->kfinal, arg->pid, arg->barrier);
  return NULL;
}

void localSearch(Points *points, long kmin, long kmax, long *kfinal) {
  pkmedian(points, kmin, kmax, kfinal, 0, nullptr);
}

void outcenterIDs(Points *centers, long *centerIDs, char *outfile) {
  FILE *fp = fopen(outfile, "w");
  if (fp == NULL) {
    fprintf(stderr, "error opening %s\n", outfile);
    exit(1);
  }
  int *is_a_median = (int *)calloc(sizeof(int), centers->num);
  for (int i = 0; i < centers->num; i++) is_a_median[centers->p[i].assign] = 1;

  for (int i = 0; i < centers->num; i++) {
    if (is_a_median[i]) {
      fprintf(fp, "%ld\n", centerIDs[i]);
      fprintf(fp, "%lf\n", centers->p[i].weight);
      for (int k = 0; k < centers->dim; k++) {
        fprintf(fp, "%lf ", centers->p[i].coord[k]);
      }
      fprintf(fp, "\n\n");
    }
  }
  fclose(fp);
  free(is_a_median);
}

void streamCluster(PStream *stream, long kmin, long kmax, int dim,
                   long chunksize, long centersize, char *outfile) {
  float *block = (float *)malloc(chunksize * dim * sizeof(float));
  float *centerBlock = (float *)malloc(centersize * dim * sizeof(float));
  long *centerIDs = (long *)malloc(centersize * dim * sizeof(long));

  if (block == NULL) {
    fprintf(stderr, "not enough memory for a chunk!\n");
    exit(1);
  }

  Points points;
  points.dim = dim;
  points.num = chunksize;
  points.p = (Point *)malloc(chunksize * sizeof(Point));
  for (int i = 0; i < chunksize; i++) points.p[i].coord = &block[i * dim];

  Points centers;
  centers.dim = dim;
  centers.p = (Point *)malloc(centersize * sizeof(Point));
  centers.num = 0;
  for (int i = 0; i < centersize; i++) {
    centers.p[i].coord = &centerBlock[i * dim];
    centers.p[i].weight = 1.0f;
  }

  long IDoffset = 0;
  long kfinal;
  while (1) {
    size_t numRead = stream->read(block, dim, chunksize);
    fprintf(stderr, "read %lu points\n", numRead);

    if (stream->ferror() || (numRead < (unsigned int)chunksize && !stream->feof())) {
      fprintf(stderr, "error reading data!\n");
      exit(1);
    }

    points.num = numRead;
    for (int i = 0; i < points.num; i++) points.p[i].weight = 1.0f;

    switch_membership = (char *)malloc(points.num * sizeof(char));
    is_center = (bool *)calloc(points.num, sizeof(bool));
    center_table = (int *)malloc(points.num * sizeof(int));

    localSearch(&points, kmin, kmax, &kfinal);

    fprintf(stderr, "finish local search\n");
    contcenters(&points);
    if (kfinal + centers.num > centersize) {
      fprintf(stderr, "oops! no more space for centers\n");
      exit(1);
    }

    copycenters(&points, &centers, centerIDs, IDoffset);
    IDoffset += numRead;

    free(is_center);
    free(switch_membership);
    free(center_table);
    if (stream->feof()) break;
  }

  switch_membership = (char *)malloc(centers.num * sizeof(char));
  is_center = (bool *)calloc(centers.num, sizeof(bool));
  center_table = (int *)malloc(centers.num * sizeof(int));

  localSearch(&centers, kmin, kmax, &kfinal);
  contcenters(&centers);
  outcenterIDs(&centers, centerIDs, outfile);

  free(is_center);
  free(switch_membership);
  free(center_table);
  free(centerIDs);
  free(block);
  free(centerBlock);
  free(points.p);
  free(centers.p);
}

int main(int argc, char **argv) {
  char *outfilename = new char[MAXNAMESIZE];
  char *infilename = new char[MAXNAMESIZE];
  long kmin, kmax, n, chunksize, clustersize;
  int dim;

#ifdef PARSEC_VERSION
#define __PARSEC_STRING(x) #x
#define __PARSEC_XSTRING(x) __PARSEC_STRING(x)
  printf("PARSEC Benchmark Suite Version " __PARSEC_XSTRING(PARSEC_VERSION) "\n");
  fflush(NULL);
#else
  printf("PARSEC Benchmark Suite\n");
  fflush(NULL);
#endif

  if (argc < 11) {
    fprintf(stderr, "usage: %s k1 k2 d n chunksize clustersize infile outfile nproc [-p platform] [-d device]\n", argv[0]);
    fprintf(stderr, "  k1:          Min. number of centers allowed\n");
    fprintf(stderr, "  k2:          Max. number of centers allowed\n");
    fprintf(stderr, "  d:           Dimension of each data point\n");
    fprintf(stderr, "  n:           Number of data points\n");
    fprintf(stderr, "  chunksize:   Number of data points to handle per step\n");
    fprintf(stderr, "  clustersize: Maximum number of intermediate centers\n");
    fprintf(stderr, "  infile:      Input file (if n<=0)\n");
    fprintf(stderr, "  outfile:     Output file\n");
    fprintf(stderr, "  nproc:       Number of threads to use\n");
    fprintf(stderr, "  platform:    Platform id\n");
    fprintf(stderr, "  device:      Device id\n\n");
    fprintf(stderr, "if n > 0, points will be randomly generated instead of reading from infile.\n");
    exit(1);
  }

  kmin = atoi(argv[1]);
  kmax = atoi(argv[2]);
  dim = atoi(argv[3]);
  n = atoi(argv[4]);
  chunksize = atoi(argv[5]);
  clustersize = atoi(argv[6]);
  strcpy(infilename, argv[7]);
  strcpy(outfilename, argv[8]);
  nproc = atoi(argv[9]);
  if (nproc <= 0) nproc = 1;
  omp_set_num_threads(nproc);
  _clCmdParams(argc, argv);

#ifdef TIMING
  gettimeofday(&tv_total_start, NULL);
#endif
  try {
    _clInit(platform_id, device_id);
  } catch (std::string msg) {
    std::cout << "exception caught in main function->" << msg << std::endl;
    return -1;
  }
#ifdef TIMING
  gettimeofday(&tv_init_end, NULL);
  tvsub(&tv_init_end, &tv_total_start, &tv);
  init_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  srand48(SEED);

  PStream *stream = nullptr;
  if (n > 0) stream = new SimStream(n);
  else stream = new FileStream(infilename);

  serial = 0.0;
  cpu_gpu_memcpy = 0.0;
  gpu_malloc = 0.0;
  gpu_free = 0.0;
  kernel = 0.0;
  cnt_speedy = 0;

  std::cout << "before sc" << std::endl;
  streamCluster(stream, kmin, kmax, dim, chunksize, clustersize, outfilename);
  std::cout << "after sc" << std::endl;

#ifdef TIMING
  gettimeofday(&tv_close_start, NULL);
#endif
  freeDevMem();
  _clRelease();
#ifdef TIMING
  gettimeofday(&tv_close_end, NULL);
  tvsub(&tv_close_end, &tv_close_start, &tv);
  close_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  delete stream;

#ifdef TIMING
  tvsub(&tv_close_end, &tv_total_start, &tv);
  total_time = tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
  printf("Init: %f\n", init_time);
  printf("MemAlloc: %f\n", mem_alloc_time);
  printf("HtoD: %f\n", h2d_time);
  printf("Exec: %f\n", kernel_time);
  printf("DtoH: %f\n", d2h_time);
  printf("Close: %f\n", close_time);
  printf("Total: %f\n", total_time);
#endif

  _clStatistics();

  delete[] outfilename;
  delete[] infilename;
  return 0;
}

#include <stdio.h>
#include <iostream>
#include <fstream>
#include <stdlib.h>
#include <sys/time.h>
#include <string.h>
#include <assert.h>
#include <math.h>
#include <sys/resource.h>
#include <limits.h>
#include <omp.h>
#include <pthread.h>
#include <vector>
#include <string>

using namespace std;

#define MAXNAMESIZE 1024
#define SEED 1
#define SP 1
#define ITER 3
#define CACHE_LINE 512
#define THREADS_PER_BLOCK 256
#define MAXBLOCKS 65536

typedef struct {
  float weight;
  float * coord;
  long assign;
  float cost;
} Point;

typedef struct {
  long num;
  int dim;
  Point *p;
} Points;

struct pkmedian_arg_t {
  Points* points;
  long kmin;
  long kmax;
  long* kfinal;
  int pid;
  pthread_barrier_t* barrier;
};

class PStream {
public:
  virtual size_t read(float* dest, int dim, int num) = 0;
  virtual int ferror() = 0;
  virtual int feof() = 0;
  virtual ~PStream() {}
};

class SimStream : public PStream {
public:
  SimStream(long n_) : n(n_) {}
  size_t read(float* dest, int dim, int num) {
    size_t count = 0;
    for (int i = 0; i < num && n > 0; i++) {
      for (int k = 0; k < dim; k++) {
        dest[i * dim + k] = lrand48() / (float)INT_MAX;
      }
      n--;
      count++;
    }
    return count;
  }
  int ferror() { return 0; }
  int feof() { return n <= 0; }
  ~SimStream() {}
private:
  long n;
};

